--
-- Table structure for table `sys_security_log`
--

DROP TABLE IF EXISTS `sys_security_log`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `sys_security_log` (
  `log_id` varchar(32) NOT NULL COMMENT '日志ID（雪花ID）',
  `tenant_id` varchar(32) NOT NULL DEFAULT '000000' COMMENT '租户ID',
  `user_id` varchar(32) DEFAULT NULL COMMENT '用户ID（匿名事件可为空）',
  `username` varchar(50) DEFAULT NULL COMMENT '用户名',
  `event_type` varchar(64) NOT NULL COMMENT '事件类型：LOGIN_FAILED/TOKEN_EXPIRED/PERMISSION_DENIED/NONCE_REPLAY/SIGNATURE_INVALID/FREQUENCY_LIMIT/BATCH_EXPORT/ROLE_CHANGE/API_KEY_CREATED/CROSS_TENANT',
  `risk_level` varchar(16) NOT NULL DEFAULT 'LOW' COMMENT '风险等级：LOW/MEDIUM/HIGH/CRITICAL',
  `title` varchar(255) NOT NULL COMMENT '事件摘要',
  `detail` text COMMENT '事件详情（JSON，不含敏感信息）',
  `route` varchar(255) DEFAULT NULL COMMENT '请求路由',
  `method` varchar(10) DEFAULT NULL COMMENT 'HTTP 方法',
  `client_ip` varchar(45) DEFAULT NULL COMMENT '客户端 IP',
  `user_agent` varchar(500) DEFAULT NULL COMMENT 'User-Agent',
  `request_id` varchar(64) DEFAULT NULL COMMENT '请求追踪 ID',
  `source` varchar(32) NOT NULL DEFAULT 'system' COMMENT '来源模块：auth/permission/replay/system',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`log_id`),
  KEY `idx_sec_tenant_time` (`tenant_id`,`create_time`),
  KEY `idx_sec_user_time` (`user_id`,`create_time`),
  KEY `idx_sec_event_type` (`event_type`,`create_time`),
  KEY `idx_sec_risk_level` (`risk_level`,`create_time`),
  KEY `idx_sec_ip` (`client_ip`,`create_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='安全审计日志表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `sys_security_log`
--

LOCK TABLES `sys_security_log` WRITE;
/*!40000 ALTER TABLE `sys_security_log` DISABLE KEYS */;
