--
-- Table structure for table `sys_storage_config`
--

DROP TABLE IF EXISTS `sys_storage_config`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `sys_storage_config` (
  `storage_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '存储配置ID',
  `tenant_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '000000' COMMENT '租户ID，000000表示平台默认配置',
  `storage_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '存储名称',
  `storage_type` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '存储类型：minio/aliyun_oss/tencent_cos/qiniu_kodo/huawei_obs/aws_s3/local',
  `endpoint` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '访问端点，不带协议，例如 s3.minion.xlcig.cn / oss-cn-hangzhou.aliyuncs.com',
  `region` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '地域，例如 oss-cn-hangzhou / ap-shanghai',
  `port` int DEFAULT NULL COMMENT '端口，MinIO常用443/9000',
  `use_ssl` tinyint NOT NULL DEFAULT '1' COMMENT '是否使用HTTPS',
  `access_key` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'AccessKey，可加密',
  `secret_key` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'SecretKey，必须加密',
  `public_bucket` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '公共桶',
  `private_bucket` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '私有桶',
  `public_base_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '公共访问基础URL',
  `private_base_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '私有访问基础URL，一般可为空',
  `path_style` tinyint NOT NULL DEFAULT '0' COMMENT '是否Path Style访问，MinIO通常为1，云厂商通常为0',
  `config_json` json DEFAULT NULL COMMENT '厂商差异配置JSON',
  `policy_json` json DEFAULT NULL COMMENT '上传限制/访问策略JSON',
  `is_default` tinyint NOT NULL DEFAULT '0' COMMENT '是否默认配置',
  `status` tinyint NOT NULL DEFAULT '1' COMMENT '状态：1启用，0停用',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `create_by` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  `update_by` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `deleted` tinyint NOT NULL DEFAULT '0',
  PRIMARY KEY (`storage_id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_storage_type` (`storage_type`),
  KEY `idx_status` (`status`),
  KEY `idx_default` (`is_default`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='对象存储配置表';
/*!40101 SET character_set_client = @saved_cs_client */;

